#include <iostream>
#include <string>
#include <vector>
using namespace std;int abbrLen(int mask,int n){int total=0;bool skip=false;for(int i=0;i<n;i++)if(mask>>i&1){if(skip){total++;skip=false;}total++;}else skip=true;return total+(skip?1:0);}string build(const string&t,int mask){string out;int run=0;for(int i=0;i<(int)t.size();i++)if(mask>>i&1){if(run){out+=to_string(run);run=0;}out+=t[i];}else run++;if(run)out+=to_string(run);return out;}string solve(const string&t,vector<string>&dict){int n=t.size();vector<int>diffs;for(auto&w:dict){if((int)w.size()!=n)continue;int d=0;for(int i=0;i<n;i++)if(t[i]!=w[i])d|=1<<i;diffs.push_back(d);}if(diffs.empty())return to_string(n);int best=0,bestLen=n+1;for(int mask=0;mask<(1<<n);mask++){bool ok=true;for(int d:diffs)if((mask&d)==0){ok=false;break;}if(ok){int l=abbrLen(mask,n);if(l<bestLen){bestLen=l;best=mask;}}}return build(t,best);}int main(){ios::sync_with_stdio(false);cin.tie(nullptr);int tcases;if(!(cin>>tcases))return 0;for(int tc=0;tc<tcases;tc++){string target;int m;cin>>target>>m;vector<string>dict(m);for(auto&w:dict)cin>>w;if(tc)cout<<"\n\n";cout<<solve(target,dict);}}
